const d = $input.first().json;

const focusLine = d.morning_focus
  ? `☀️ Bugünün odağı: "${d.morning_focus}"\n\n`
  : '';

const scheduleBlock = d.schedule.length
  ? d.schedule.map(g => `  ${g.start_time || '--:--'} ${g.title}`).join('\n')
  : '  (Program henüz oluşturulmamış — uygulamayı aç ve planla)';

const habitsBlock = d.active_habits.length
  ? d.active_habits.map(h => {
      const time = h.preferred_time ? ` [${h.preferred_time}]` : '';
      const mini = h.two_minute_version ? ` — 2 dk: ${h.two_minute_version}` : '';
      return `  • ${h.name}${time}${mini}`;
    }).join('\n')
  : '  (Alışkanlık tanımlanmamış)';

const subject = `☀️ Atomik Planner — ${d.date} Sabah Planın`;
const body = `Günaydın! ${d.date}\n\n` +
  focusLine +
  `📅 Bugünün programı:\n${scheduleBlock}\n\n` +
  `💪 Aktif alışkanlıkların:\n${habitsBlock}`;

return [{ json: { subject, body } }];
